import Image from 'next/image';
import Link from 'next/link';

type Cta = { label: string; href: string };

type HeroBannerProps = {
  title: string;
  subtitle?: string;
  image: { src: string; alt: string };
  cta?: Cta;
};

export function HeroBanner({ title, subtitle, image, cta }: HeroBannerProps) {
  return (
    <section className="relative h-[80vh] min-h-[480px] overflow-hidden">
      <div className="absolute inset-0 will-change-transform" data-parallax>
        <Image
          src={image.src}
          alt={image.alt}
          fill
          priority
          sizes="100vw"
          className="object-cover"
        />
        <div className="absolute inset-0 bg-gradient-to-b from-black/30 via-black/40 to-black/70" />
      </div>
      <div className="relative z-10 container mx-auto h-full flex flex-col justify-end pb-16 px-6">
        <h1 className="max-w-2xl text-balance text-5xl md:text-6xl font-bold text-white animate-in fade-in slide-in-from-bottom-4 duration-700">
          {title}
        </h1>
        {subtitle && (
          <p className="mt-4 max-w-xl text-lg text-white/85">{subtitle}</p>
        )}
        {cta && (
          <Link
            href={cta.href}
            className="mt-8 inline-flex w-fit items-center gap-2 rounded-full bg-primary px-6 py-3 font-medium text-primary-foreground hover:bg-primary/90"
          >
            {cta.label}
          </Link>
        )}
      </div>
    </section>
  );
}

type Feature = { icon: string; title: string; body: string };

export function FeatureGrid({ heading, features }: { heading?: string; features: Feature[] }) {
  return (
    <section className="container mx-auto px-6 py-20">
      {heading && (
        <h2 className="text-3xl md:text-4xl font-semibold tracking-tight mb-10">
          {heading}
        </h2>
      )}
      <div className="grid gap-8 sm:grid-cols-2 lg:grid-cols-3">
        {features.map((f, i) => (
          <article
            key={f.title}
            className="rounded-xl border border-border p-6 animate-in fade-in slide-in-from-bottom-2"
            style={{ animationDelay: `${i * 80}ms` }}
          >
            <div className="text-primary text-2xl mb-4" aria-hidden>
              {f.icon}
            </div>
            <h3 className="font-semibold text-lg mb-2">{f.title}</h3>
            <p className="text-muted-foreground text-sm leading-relaxed">{f.body}</p>
          </article>
        ))}
      </div>
    </section>
  );
}

type Plan = {
  name: string;
  monthly: number;
  annual: number;
  recommended?: boolean;
  features: string[];
  cta: { label: string; href: string };
};

export function PricingTable({ plans }: { plans: Plan[] }) {
  return (
    <section className="container mx-auto px-6 py-20">
      <div className="grid gap-6 lg:grid-cols-3">
        {plans.map((p) => (
          <div
            key={p.name}
            className={
              'rounded-2xl border p-8 ' +
              (p.recommended ? 'border-primary shadow-lg' : 'border-border')
            }
          >
            {p.recommended && (
              <div className="text-xs font-medium text-primary mb-2">Recommended</div>
            )}
            <h3 className="text-2xl font-semibold">{p.name}</h3>
            <p className="mt-4 text-4xl font-bold">${p.monthly}<span className="text-base font-normal text-muted-foreground">/mo</span></p>
            <ul className="mt-6 space-y-2 text-sm">
              {p.features.map((f) => (
                <li key={f}>· {f}</li>
              ))}
            </ul>
            <a
              href={p.cta.href}
              className="mt-8 inline-flex w-full items-center justify-center rounded-md bg-primary px-4 py-2 font-medium text-primary-foreground"
            >
              {p.cta.label}
            </a>
          </div>
        ))}
      </div>
    </section>
  );
}
